class QueueUsingTwoStacks:
    def __init__(self):
        self._stack_enqueue = []
        self._stack_dequeue = []

    def _transfer_elements_if_needed(self):
        if not self._stack_dequeue:
            if not self._stack_enqueue:
                raise IndexError("Queue is empty")
            while self._stack_enqueue:
                self._stack_dequeue.append(self._stack_enqueue.pop())

    def enqueue(self, item):
        self._stack_enqueue.append(item)

    def dequeue(self):
        self._transfer_elements_if_needed()
        return self._stack_dequeue.pop()

    def peek(self):
        self._transfer_elements_if_needed()
        return self._stack_dequeue[-1]

    def is_empty(self):
        return not self._stack_enqueue and not self._stack_dequeue

    def size(self):
        return len(self._stack_enqueue) + len(self._stack_dequeue)
